export const getListBorrowsUrl = (params?: ListBorrowsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/borrows?${stringifiedParams}`
    : `/api/borrows`;
};

export const listBorrows = async (
  params?: ListBorrowsParams,
  options?: RequestInit,
): Promise<Borrow[]> => {
  return customFetch<Borrow[]>(getListBorrowsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListBorrowsQueryKey = (params?: ListBorrowsParams) => {
  return [`/api/borrows`, ...(params ? [params] : [])] as const;
};

export const getListBorrowsQueryOptions = <
  TData = Awaited<ReturnType<typeof listBorrows>>,
  TError = ErrorType<unknown>,
>(
  params?: ListBorrowsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listBorrows>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getListBorrowsQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listBorrows>>> = ({
    signal,
  }) => listBorrows(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listBorrows>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

